/// Cached floor layer — built once on first access.
TileLayerData? _cachedFloorLayer;

/// Builds (or returns cached) floor [TileLayerData] for the L-Room.
///
/// Creates 2,500 [TileRef] objects on first call; subsequent calls return the
/// same instance.
TileLayerData buildLRoomFloorLayer() {
  if (_cachedFloorLayer != null) return _cachedFloorLayer!;
  final layer = TileLayerData();
  for (var y = 0; y < _tileIndices.length; y++) {
    final row = _tileIndices[y];
    for (var x = 0; x < row.length; x++) {
      layer.setTile(x, y, TileRef(tilesetId: 'single_room', tileIndex: row[x]));
    }
  }
  _cachedFloorLayer = layer;
  return layer;
}

// ---------------------------------------------------------------------------
// Object layer — wall tiles with y-priority for depth-sorted occlusion.
// ---------------------------------------------------------------------------

/// Barrier positions for the L-Room.
const _barriers = [
  // Vertical wall at x=4 (gap at y=17 for door)
  (4, 7), (4, 8), (4, 9), (4, 10), (4, 11),
  (4, 12), (4, 13), (4, 14), (4, 15), (4, 16),
  (4, 18), (4, 19), (4, 20), (4, 21), (4, 22),
  (4, 23), (4, 24), (4, 25), (4, 26), (4, 27),
  (4, 28), (4, 29),
  // Horizontal wall at y=7
  (5, 7), (6, 7), (7, 7), (8, 7), (9, 7),
  (10, 7), (11, 7), (12, 7), (13, 7), (14, 7),
  (15, 7), (16, 7), (17, 7),
];

/// Set of barrier positions for quick lookup.
final _barrierSet = {for (final b in _barriers) b};

/// North-facing barrier edges — barriers with open space above them.
///
/// These are the only barriers where a player can stand directly above,
/// so they're the only ones that need wall-cap occlusion.
final List<(int, int)> _northFacingEdges = _barriers
    .where((b) => !_barrierSet.contains((b.$1, b.$2 - 1)))
    .toList();

/// Doorway lintels — barriers above a gap with another barrier below the gap.
///
/// Pattern: barrier at y, open at y+1, barrier at y+2. The player walks
/// through the gap at y+1 and should be occluded by the lintel at y. Only
/// (4, 16) qualifies in the L-Room (door gap at y=17, wall resumes at y=18).
///
/// Regular south-facing edges (like the horizontal wall bottom at y=7) are
/// excluded — players south of a wall should appear in front, not behind.
final List<(int, int)> _doorwayLintels = _barriers
    .where((b) =>
        !_barrierSet.contains((b.$1, b.$2 + 1)) &&
        _barrierSet.contains((b.$1, b.$2 + 2)))
    .toList();

/// Cached object layer.
TileLayerData? _cachedObjectLayer;

/// Builds the object layer for the L-Room containing wall tiles at barrier
/// positions, wall caps (1 row above north-facing edges), and extended
/// occlusion tiles above doorway lintels.
///
/// These tiles render with y-priority in the World, enabling players to
/// walk behind walls. The floor layer keeps the same tiles underneath —
/// harmless duplication that prevents gaps when the object layer is hidden.
TileLayerData buildLRoomObjectLayer() {
  if (_cachedObjectLayer != null) return _cachedObjectLayer!;
  final layer = TileLayerData();

  // Add all barrier tiles.
  for (final (x, y) in _barriers) {
    layer.setTile(
      x, y,
      TileRef(tilesetId: 'single_room', tileIndex: _tileIndices[y][x]),
    );
  }

  // Add wall cap tiles (1 row above each north-facing edge).
  for (final (x, y) in _northFacingEdges) {
    final capY = y - 1;
    if (capY >= 0) {
      layer.setTile(
        x, capY,
        TileRef(tilesetId: 'single_room', tileIndex: _tileIndices[capY][x]),
      );
    }
  }

  // Extended occlusion above doorway lintels. The player sprite is 64px
  // tall (2 grid cells). A single lintel tile only covers 32px, so the
  // player's head peeks over. Adding the tile above the lintel extends
  // the occlusion zone to match the player's full height. The tile may
  // already be in the layer (as a barrier) — setTile is idempotent.
  for (final (x, y) in _doorwayLintels) {
    final aboveY = y - 1;
    if (aboveY >= 0) {
      layer.setTile(
        x, aboveY,
        TileRef(tilesetId: 'single_room', tileIndex: _tileIndices[aboveY][x]),
      );
    }
  }

  _cachedObjectLayer = layer;
  return layer;
}

/// Priority overrides for wall tiles that need non-natural priority.
///
/// **Wall caps** (1 row above north-facing edges): bumped to the barrier's y
/// so they sort with the wall face. Without this, a cap at y=6 and a player
/// at y=6 would have the same priority — ambiguous rendering order.
///
/// **Door lintels**: bumped to `y + 2` so they render on top of a player
/// walking through the gap at `y + 1`. Needs +2 (not +1) because the
/// player in the gap has priority `y + 1`, and we need strictly greater.
Map<(int, int), int> buildLRoomPriorityOverrides() {
  return {
    // Wall caps: priority = barrier y (one row below).
    for (final (x, y) in _northFacingEdges)
      if (y - 1 >= 0) (x, y - 1): y,
    // Door lintels: priority bumped to gap y + 1 so the lintel renders on
    // top of a player in the gap.
    for (final (x, y) in _doorwayLintels) (x, y): y + 2,
    // Extended occlusion above lintels: same elevated priority so the tile
    // above the lintel also occludes the player's head. This tile may be
    // another barrier (already in the object layer) — the override bumps
    // its priority to match the lintel.
    for (final (x, y) in _doorwayLintels)
      if (y - 1 >= 0) (x, y - 1): y + 2,
  };
}
